import subprocess, sys, itertools

TMPL = """;redcode-94
;name ClearV
;assert CORESIZE == 8000
dec   equ {dec}
gate  equ clear-4
      org clear-1
bptr  dat bomb, {off}
bomb  spl #dec, 11
clear {movs}      djn.f clear, }}bomb
      end
"""

def battle(fn, opp, r=100):
    out = subprocess.run(['pmars','-b','-r',str(r),'-f',fn,f'warriors/{opp}.red'],
                         capture_output=True,text=True).stdout
    for line in out.splitlines():
        if line.startswith('Results:'):
            a,b,t = map(int,line.split()[1:4])
            return a,b,t
    return None

def make(nmov, dec, off, fn='/tmp/v.red'):
    movs = ''.join('mov *bptr, >gate\n      ' for _ in range(nmov))
    open(fn,'w').write(TMPL.format(dec=dec, off=off, movs=movs))
    return fn

